import base64
import io
import pygame
import random
import math
import time

# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
#  초기 설정 및 상수
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
pygame.init()
pygame.mixer.init()

# BGM 시작 (파일 로딩)
try:
    if not pygame.mixer.music.get_busy():
        pygame.mixer.music.load("assets/sound/bitbgm.mp3")
        pygame.mixer.music.play(-1)
except Exception as e:
    print(f"BGM 로드 실패: {e}")

SCREEN_W, SCREEN_H = 800, 600
GRID_SIZE = 20

COLOR_BG = (15, 15, 25)
COLOR_SNAKE = (50, 255, 100)
COLOR_WALL = (60, 60, 80)
COLOR_PILL = (255, 100, 100)
COLOR_MEGAPILL = (255, 50, 50)
COLOR_BURGER = (200, 150, 50)
COLOR_SNACK = (100, 200, 255)
COLOR_PORTAL = (200, 50, 255)
COLOR_TEXT = (255, 255, 255)
COLOR_YOYO = (255, 50, 50)

INITIAL_WEIGHT = 25
MAX_WEIGHT = 35
SEGMENT_DISTANCE = 10 
YOYO_BASE_RATE = 0.05
GHOST_DURATION = 0.5
FPS = 60

# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
#  에셋 데이터 (Base64 임베딩)
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
# boom.wav (정확한 Base64 데이터)
BOOM_B64 = ""

screen = pygame.display.set_mode((SCREEN_W, SCREEN_H))
pygame.display.set_caption("Snake Diet: 360 Free Movement")
clock = pygame.time.Clock()
font_ui = pygame.font.SysFont("malgungothic", 20, bold=True)
font_msg = pygame.font.SysFont("malgungothic", 60, bold=True)

class Snake:
    def __init__(self):
        self.reset()
        self._init_sprites()

    def _init_sprites(self):
        # 뱀 스프라이트 시트 로드 (assets/image/Snake.png)
        try:
            full_sheet = pygame.image.load("assets/image/Snake.png").convert_alpha()
            
            # 64x64 시트, 각 셀은 16x16
            # 머리 (오른쪽 보기): x=48, y=0
            self.head_img = full_sheet.subsurface(pygame.Rect(48, 0, 16, 16))
            self.head_img = pygame.transform.scale(self.head_img, (GRID_SIZE*2, GRID_SIZE*2))
            
            # 몸통 (연결된 블록): x=16, y=48 (가로형 직사각형 몸통)
            self.body_img = full_sheet.subsurface(pygame.Rect(16, 48, 16, 16))
            self.body_img = pygame.transform.scale(self.body_img, (GRID_SIZE+6, GRID_SIZE+6))
           
            # 토끼 (아이템): x=32, y=48
            self.rabbit_img = full_sheet.subsurface(pygame.Rect(32, 48, 16, 16))
            self.rabbit_img = pygame.transform.scale(self.rabbit_img, (GRID_SIZE+8, GRID_SIZE+8))
        except Exception as e:
            print(f"스프라이트 로드 실패: {e}")
            # 백업용 빈 서피스
            self.head_img = pygame.Surface((GRID_SIZE*2, GRID_SIZE*2), pygame.SRCALPHA)
            self.body_img = pygame.Surface((GRID_SIZE, GRID_SIZE), pygame.SRCALPHA)
            self.rabbit_img = pygame.Surface((GRID_SIZE, GRID_SIZE), pygame.SRCALPHA)

        # 효과음 로드 (Base64 임베딩 데이터 사용)
        try:
            sound_data = base64.b64decode(BOOM_B64)
            self.boom_sound = pygame.mixer.Sound(io.BytesIO(sound_data))
            self.boom_sound.set_volume(0.5)
        except Exception as e:
            print(f"효과음 로드 실패: {e}")
            self.boom_sound = None

    def reset(self):
        self.x, self.y = SCREEN_W // 2, SCREEN_H // 2
        self.angle = 0.0 # 0 ~ 2*PI
        self.weight = INITIAL_WEIGHT
        
        # 실제 세그먼트 좌표들 (일렬로 배치하여 시작 시 충돌 방지)
        self.segments = [[self.x - i * SEGMENT_DISTANCE, self.y] for i in range(self.weight)]
        # 경로 히스토리 (마디 추적용)
        self.path_history = [(self.x - i, self.y) for i in range(self.weight * SEGMENT_DISTANCE + 10)]
        
        self.speed = 3.0
        self.turn_speed = 0.1
        self.ghost_timer = 0
        self.yoyo_gauge = 0
        self.frozen_timer = 0
        self.alive = True
        self.won = False

    def handle_input(self):
        keys = pygame.key.get_pressed()
        if keys[pygame.K_LEFT]:
            self.angle -= self.turn_speed
        if keys[pygame.K_RIGHT]:
            self.angle += self.turn_speed
        
        if keys[pygame.K_SPACE] and self.ghost_timer <= 0:
            self.ghost_timer = GHOST_DURATION
            self.yoyo_gauge = min(100, self.yoyo_gauge + 40)

    def update(self, dt):
        if not self.alive or self.won: return

        # 타이머 처리
        if self.ghost_timer > 0: self.ghost_timer -= dt / 1000.0
        if self.frozen_timer > 0: self.frozen_timer -= dt / 1000.0

        # 요요 게이지
        if self.frozen_timer <= 0:
            self.yoyo_gauge += YOYO_BASE_RATE * (dt / 5.0)
            if self.yoyo_gauge >= 100:
                self.yoyo_gauge = 0
                self.grow()

        # 속도 조절
        self.speed = 6.5 - (self.weight / 6.0)
        self.speed = max(3.0, min(7.5, self.speed))

        # 이동 계산
        self.x += math.cos(self.angle) * self.speed
        self.y += math.sin(self.angle) * self.speed

        # 벽 충돌
        if self.ghost_timer > 0:
            self.x %= SCREEN_W
            self.y %= SCREEN_H
        else:
            if not (0 <= self.x < SCREEN_W and 0 <= self.y < SCREEN_H):
                self.alive = False
                if self.boom_sound: self.boom_sound.play()

        # 경로 기록
        self.path_history.insert(0, (self.x, self.y))
        max_history = MAX_WEIGHT * SEGMENT_DISTANCE + 10
        if len(self.path_history) > max_history:
            self.path_history.pop()

        # 마디 좌표 갱신
        for i in range(self.weight):
            idx = i * SEGMENT_DISTANCE
            if idx < len(self.path_history):
                self.segments[i] = self.path_history[idx]

        # 자기 충돌
        if self.ghost_timer <= 0 and self.weight > 5:
            head = self.segments[0]
            for i in range(15, self.weight):
                seg = self.segments[i]
                dist = math.hypot(head[0]-seg[0], head[1]-seg[1])
                if dist < 12:
                    self.alive = False
                    if self.boom_sound: self.boom_sound.play()
                    break

    def grow(self, amount=1):
        for _ in range(amount):
            if self.weight < MAX_WEIGHT:
                self.weight += 1
                self.segments.append(self.segments[-1])
            else:
                self.alive = False 
                if self.boom_sound: self.boom_sound.play()

    def shrink(self, amount=1):
        for _ in range(amount):
            if self.weight > 1:
                self.weight -= 1
                self.segments.pop()
        self.yoyo_gauge = 0
        if self.boom_sound: self.boom_sound.play()

    def draw(self, surface):
        # 몸통부터 그리기 (머리가 가장 나중에 그려지도록 꼬리부터 루프)
        alpha = 150 if self.ghost_timer > 0 else 255
        
        for i in range(self.weight - 1, -1, -1):
            pos = self.segments[i]
            
            if i == 0:
                # 머리 출력: 기본 이미지가 반대 방향을 보고 있었으므로 +90도 보정으로 수정
                rotated_head = pygame.transform.rotate(self.head_img, -math.degrees(self.angle) + 90)
                if self.ghost_timer > 0: rotated_head.set_alpha(alpha)
                rect = rotated_head.get_rect(center=pos)
                surface.blit(rotated_head, rect.topleft)
            else:
                # 몸통은 앞마디(i-1)와의 관계를 통해 각도 계산
                prev_pos = self.segments[i-1]
                dx = prev_pos[0] - pos[0]
                dy = prev_pos[1] - pos[1]
                
                # 움직임이 있을 때만 각도 갱신 (제자리에 뭉쳐있을 때 튀는 현상 방지)
                if dx != 0 or dy != 0:
                    seg_angle = math.atan2(dy, dx)
                    rotated_body = pygame.transform.rotate(self.body_img, -math.degrees(seg_angle))
                else:
                    rotated_body = self.body_img
                    
                if self.ghost_timer > 0:
                    rotated_body.set_alpha(alpha)
                else:
                    rotated_body.set_alpha(255)
                    
                rect = rotated_body.get_rect(center=pos)
                surface.blit(rotated_body, rect.topleft)

class Game:
    def __init__(self):
        self.snake = Snake()
        self.items = []
        self.portal_pos = None
        self.portal_timer = 0
        self._init_item_surfs()
        self.spawn_item()

    def _init_item_surfs(self):
        self.item_surfs = {}
        for name, color in [("PILL", COLOR_PILL), ("MEGAPILL", COLOR_MEGAPILL), ("BURGER", COLOR_BURGER), ("SNACK", COLOR_SNACK)]:
            if name in ["BURGER", "SNACK"] and hasattr(self.snake, "rabbit_img"):
                self.item_surfs[name] = self.snake.rabbit_img
            else:
                surf = pygame.Surface((24, 24), pygame.SRCALPHA)
                pygame.draw.circle(surf, color, (12, 12), 10)
                pygame.draw.circle(surf, (255, 255, 255, 100), (12, 12), 12, 2)
                self.item_surfs[name] = surf
        
        self.portal_surf = pygame.Surface((40, 40), pygame.SRCALPHA)
        pygame.draw.circle(self.portal_surf, COLOR_PORTAL, (20, 20), 18, 4)
        pygame.draw.circle(self.portal_surf, COLOR_PORTAL, (20, 20), 8)

    def spawn_item(self):
        while len(self.items) < 4:
            x, y = random.randint(50, SCREEN_W-50), random.randint(50, SCREEN_H-50)
            r = random.random()
            if r < 0.6: type = "PILL"
            elif r < 0.75: type = "MEGAPILL"
            elif r < 0.85: type = "BURGER"
            else: type = "SNACK"
            self.items.append({"pos": (x, y), "type": type})

    def update(self, dt):
        self.snake.handle_input()
        self.snake.update(dt)
        
        if not self.snake.alive or self.snake.won: return

        head = self.snake.segments[0]
        # 아이템 충돌
        for item in self.items[:]:
            dist = math.hypot(head[0]-item["pos"][0], head[1]-item["pos"][1])
            if dist < 25:
                t = item["type"]
                if t == "PILL": self.snake.shrink(1)
                elif t == "MEGAPILL": self.snake.shrink(3)
                elif t == "BURGER": self.snake.grow(2)
                elif t == "SNACK": self.snake.frozen_timer = 5.0
                self.items.remove(item)
                self.spawn_item()

        # 탈출 포탈
        if self.snake.weight == 1:
            if self.portal_pos is None: self.spawn_portal()
            self.portal_timer -= dt / 1000.0
            if self.portal_timer <= 0: self.spawn_portal()
            
            dist = math.hypot(head[0]-self.portal_pos[0], head[1]-self.portal_pos[1])
            if dist < 30: self.snake.won = True
        else:
            self.portal_pos = None

    def spawn_portal(self):
        self.portal_pos = (random.randint(100, SCREEN_W-100), random.randint(100, SCREEN_H-100))
        self.portal_timer = 5.0

    def draw(self):
        screen.fill(COLOR_BG)
        
        # 격자 무늬
        for i in range(0, SCREEN_W, 100):
            pygame.draw.line(screen, (30, 30, 40), (i, 0), (i, SCREEN_H))
        for i in range(0, SCREEN_H, 100):
            pygame.draw.line(screen, (30, 30, 40), (0, i), (SCREEN_W, i))

        for item in self.items:
            rect = self.item_surfs[item["type"]].get_rect(center=item["pos"])
            screen.blit(self.item_surfs[item["type"]], rect.topleft)

        if self.portal_pos:
            rect = self.portal_surf.get_rect(center=self.portal_pos)
            screen.blit(self.portal_surf, rect.topleft)

        self.snake.draw(screen)

        # UI
        weight_txt = font_ui.render(f"WEIGHT: {self.snake.weight} / {MAX_WEIGHT}", True, COLOR_TEXT)
        screen.blit(weight_txt, (20, 20))
        
        pygame.draw.rect(screen, (40, 40, 50), (20, 50, 200, 12), border_radius=6)
        pygame.draw.rect(screen, COLOR_YOYO, (20, 50, 200 * (self.snake.yoyo_gauge/100), 12), border_radius=6)
        
        if self.snake.frozen_timer > 0:
            f_txt = font_ui.render(f"FROZEN: {self.snake.frozen_timer:.1f}s", True, COLOR_SNACK)
            screen.blit(f_txt, (20, 70))

        if not self.snake.alive:
            msg = font_msg.render("GAME OVER", True, (255, 50, 50))
            screen.blit(msg, (SCREEN_W//2 - msg.get_width()//2, SCREEN_H//2 - 40))
        if self.snake.won:
            msg = font_msg.render("SUCCESS!", True, (100, 255, 255))
            screen.blit(msg, (SCREEN_W//2 - msg.get_width()//2, SCREEN_H//2 - 40))

        pygame.display.flip()

def main():
    game = Game()
    while True:
        dt = clock.tick(FPS)
        for event in pygame.event.get():
            if event.type == pygame.QUIT: pygame.quit(); return
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_r: game = Game()
                if event.key == pygame.K_ESCAPE: pygame.quit(); return
        
        game.update(dt)
        game.draw()

if __name__ == "__main__":
    main()
